import React, { useEffect } from "react";
import { Link } from "react-router-dom";
import "../styles/inicio.css"; // ✅ corregido

const Financiero = () => {

  useEffect(() => {
    const year = document.getElementById("year");
    if (year) {
      year.textContent = new Date().getFullYear();
    }

    window.history.pushState(null, "", window.location.href);

    window.onpopstate = function () {
      window.history.go(1);
    };

    const handleKeyDown = (e) => {
      if (
        (e.altKey && e.key === "ArrowLeft") ||
        (e.altKey && e.key === "ArrowRight")
      ) {
        e.preventDefault();
      }
    };

    document.addEventListener("keydown", handleKeyDown);

    return () => {
      document.removeEventListener("keydown", handleKeyDown);
    };
  }, []);

  return (
    <>
      {/* HEADER */}
      <header className="site-header">
        <div className="container">
          <nav className="navbar">
            <h2 className="logo">Financiero</h2>

            <ul className="nav-links">
              <li>Cuenta</li>
              <li>Certificado</li>
              <li>Bre-be</li>
              <li><Link to="/login" className="btn-nav">Inicio</Link>
              </li>
              <li>
                <Link to="/registro" className="btn-nav">Registro</Link>
              </li>
            </ul>
          </nav>
        </div>
      </header>

      {/* MAIN */}
      <main>

        {/* HERO */}
        <section className="hero container">
          <div className="hero-text">
            <h1>Compromiso Financiero</h1>

            <p>
              Somos una compañía financiera nueva que está transformando lo ya existente
              en algo diferente. Comprender los problemas actuales de los usuarios
              y empresas es crucial para construir un servicio más robusto y confiable.
            </p>

            <Link to="/registro" className="btn-main">
              Registrarse
            </Link>
          </div>

          <div className="hero-img">
            <div className="circle"></div>
          </div>
        </section>

        {/* GARANTÍAS */}
        <section className="garantias container">
          <h2>Las Garantías De Nuestro Compromiso Financiero</h2>

          <div className="garantias-grid">

            {[
              ["💲", "Seguridad del dinero", "El dinero quedará asegurado en todo momento."],
              ["🔒", "Seguridad al iniciar sesión", "Garantía total de seguridad al acceder a tu cuenta."],
              ["🔁", "Transferencias", "Transferencias seguras entre bancos rápidas y confiables."],
              ["🔄", "Actualización de movimientos", "Historial actualizado en tiempo real."],
              ["🚫", "Bloqueo rápido", "Bloqueo eficiente en caso de robo o actividades sospechosas."],
              ["📄", "Certificado bancario", "Documento oficial que confirma la existencia de tu cuenta."]
            ].map((item, i) => (
              <div key={i} className="garantia-card">
                <div className="garantia-content">
                  <div className="garantia-icon">{item[0]}</div>
                  <div>
                    <h3>{item[1]}</h3>
                    <p>{item[2]}</p>
                  </div>
                </div>
              </div>
            ))}

          </div>
        </section>

      </main>

      {/* FOOTER */}
      <footer className="site-footer">
        <div className="container">
          <p>
            © <span id="year"></span> Financiero — Todos los derechos reservados
          </p>
        </div>
      </footer>
    </>
  );
};

export default Financiero;
